import React, { useState } from 'react';
import { PremblyPass } from 'prembly-pass';

function FaceLiveliness() {
  const [verificationSuccess, setVerificationSuccess] = useState(false);

  const handleVerify = () => {
    // Initialize PremblyPass with credentials
    const prembly = new PremblyPass({
      app_id: process.env.REACT_APP_PREMBLY_APP_ID,
      x_api_key: process.env.REACT_APP_PREMBLY_API_KEY,
      environment: 'test'
    });

    // Launch the widget with config_id and user_ref
    prembly.launch({
      config_id: process.env.REACT_APP_PREMBLY_CONFIG_ID,
      user_ref: 'user_123',
      onSuccess: (response) => {
        console.log('Verification successful:', response);
        setVerificationSuccess(true);
      },
      onError: (error) => {
        console.error('Verification failed:', error);
      }
    });
  };

  return (
    <div className="face-liveliness-container">
      <h1>Face Liveliness Verification</h1>
      <button 
        id="verify-btn" 
        onClick={handleVerify}
        style={{
          padding: '12px 24px',
          fontSize: '16px',
          backgroundColor: '#007bff',
          color: 'white',
          border: 'none',
          borderRadius: '4px',
          cursor: 'pointer',
          marginTop: '20px'
        }}
      >
        Start Verification
      </button>
      {verificationSuccess && (
        <div 
          id="success-message" 
          style={{
            marginTop: '20px',
            padding: '12px',
            backgroundColor: '#d4edda',
            color: '#155724',
            border: '1px solid #c3e6cb',
            borderRadius: '4px'
          }}
        >
          Verification successful
        </div>
      )}
    </div>
  );
}

export default FaceLiveliness;

